						{
							averageProfilerTimingsOverASecond = value;
						}
					},
					(DebugUI.Widget)new DebugUI.BoolField
					{
						displayName = "Hide empty scopes",
						tooltip = "Hide profiling scopes where elapsed time in each category is zero",
