			ArrayExtensions.ResizeArray(ref normalToDecals, newCapacity);
			ArrayExtensions.ResizeArray(ref renderingLayerMasks, newCapacity);
			ArrayExtensions.ResizeArray(ref subCalls, newCapacity);
			base.capacity = newCapacity;
		}

		public override void Dispose()
		{
			subCallCounts.Dispose();
			if (base.capacity != 0)
			{
				decalToWorlds.Dispose();
				normalToDecals.Dispose();
				renderingLayerMasks.Dispose();
				subCalls.Dispose();
				base.count = 0;
				base.capacity = 0;
			}
		}
	}
	internal class DecalCreateDrawCallSystem
	{
		[BurstCompile]
		private struct DrawCallJob : IJob
		{
			[Unity.Collections.ReadOnly]
			public NativeArray<float4x4> decalToWorlds;

			[Unity.Collections.ReadOnly]
			public NativeArray<float4x4> normalToWorlds;

			[Unity.Collections.ReadOnly]
			public NativeArray<float4x4> sizeOffsets;

			[Unity.Collections.ReadOnly]
			public NativeArray<float2> drawDistances;

			[Unity.Collections.ReadOnly]
			public NativeArray<float2> angleFades;

			[Unity.Collections.ReadOnly]
			public NativeArray<float4> uvScaleBiases;

			[Unity.Collections.ReadOnly]
			public NativeArray<int> layerMasks;

			[Unity.Collections.ReadOnly]
			public NativeArray<ulong> sceneLayerMasks;

			[Unity.Collections.ReadOnly]
			public NativeArray<float> fadeFactors;

			[Unity.Collections.ReadOnly]
			public NativeArray<BoundingSphere> boundingSpheres;

			[Unity.Collections.ReadOnly]
			public NativeArray<uint> renderingLayerMasks;

			public Vector3 cameraPosition;

			public ulong sceneCullingMask;

			public int cullingMask;

			[Unity.Collections.ReadOnly]
			public NativeArray<int> visibleDecalIndices;

			public int visibleDecalCount;

			public float maxDrawDistance;

			[WriteOnly]
			public NativeArray<float4x4> decalToWorldsDraw;

			[WriteOnly]
			public NativeArray<float4x4> normalToDecalsDraw;

			[WriteOnly]
			public NativeArray<float> renderingLayerMasksDraw;

			[WriteOnly]
			public NativeArray<DecalSubDrawCall> subCalls;

			[WriteOnly]
			public NativeArray<int> subCallCount;

			public void Execute()
			{
				int value = 0;
				int num = 0;
				int num2 = 0;
				for (int i = 0; i < visibleDecalCount; i++)
				{
					int index = visibleDecalIndices[i];
					int num3 = 1 << layerMasks[index];
					if ((cullingMask & num3) == 0)
					{
						continue;
					}
					BoundingSphere boundingSphere = boundingSpheres[index];
					float2 float5 = drawDistances[index];
					float magnitude = (cameraPosition - boundingSphere.position).magnitude;
					float num4 = math.min(float5.x, maxDrawDistance) + boundingSphere.radius;
					if (!(magnitude > num4))
					{
						decalToWorldsDraw[num] = decalToWorlds[index];
						float num5 = fadeFactors[index];
						float2 float6 = angleFades[index];
						float4 float7 = uvScaleBiases[index];
						float4x4 value2 = normalToWorlds[index];
						float num6 = num5 * math.clamp((num4 - magnitude) / (num4 * (1f - float5.y)), 0f, 1f);
						value2.c0.w = float7.x;
						value2.c1.w = float7.y;
						value2.c2.w = float7.z;
						value2.c3 = new float4(num6 * 1f, float6.x, float6.y, float7.w);
						normalToDecalsDraw[num] = value2;
						renderingLayerMasksDraw[num] = renderingLayerMasks[index];
						num++;
						if (num - num2 >= DecalDrawSystem.MaxBatchSize)
						{
							subCalls[value++] = new DecalSubDrawCall
							{
								start = num2,
								end = num
							};
							num2 = num;
						}
					}
				}
				if (num - num2 != 0)
				{
					subCalls[value++] = new DecalSubDrawCall
					{
						start = num2,
						end = num
					};
				}
				subCallCount[0] = value;
			}
		}

		private DecalEntityManager m_EntityManager;

		private ProfilingSampler m_Sampler;

		private float m_MaxDrawDistance;

		public float maxDrawDistance
		{
			get
			{
				return m_MaxDrawDistance;
			}
			set
			{
				m_MaxDrawDistance = value;
			}
		}

		public DecalCreateDrawCallSystem(DecalEntityManager entityManager, float maxDrawDistance)
		{
			m_EntityManager = entityManager;
			m_Sampler = new ProfilingSampler("DecalCreateDrawCallSystem.Execute");
			m_MaxDrawDistance = maxDrawDistance;
		}

		public void Execute()
		{
			using (new ProfilingScope(m_Sampler))
			{
				for (int i = 0; i < m_EntityManager.chunkCount; i++)
				{
					Execute(m_EntityManager.cachedChunks[i], m_EntityManager.culledChunks[i], m_EntityManager.drawCallChunks[i], m_EntityManager.cachedChunks[i].count);
				}
			}
		}

		private void Execute(DecalCachedChunk cachedChunk, DecalCulledChunk culledChunk, DecalDrawCallChunk drawCallChunk, int count)
		{
			if (count != 0)
			{
				JobHandle currentJobHandle = (drawCallChunk.currentJobHandle = new DrawCallJob
				{
					decalToWorlds = cachedChunk.decalToWorlds,
					normalToWorlds = cachedChunk.normalToWorlds,
					sizeOffsets = cachedChunk.sizeOffsets,
					drawDistances = cachedChunk.drawDistances,
					angleFades = cachedChunk.angleFades,
					uvScaleBiases = cachedChunk.uvScaleBias,
					layerMasks = cachedChunk.layerMasks,
					sceneLayerMasks = cachedChunk.sceneLayerMasks,
					fadeFactors = cachedChunk.fadeFactors,
					boundingSpheres = cachedChunk.boundingSpheres,
					renderingLayerMasks = cachedChunk.renderingLayerMasks,
					cameraPosition = culledChunk.cameraPosition,
					sceneCullingMask = culledChunk.sceneCullingMask,
					cullingMask = culledChunk.cullingMask,
					visibleDecalIndices = culledChunk.visibleDecalIndices,
					visibleDecalCount = culledChunk.visibleDecalCount,
					maxDrawDistance = m_MaxDrawDistance,
					decalToWorldsDraw = drawCallChunk.decalToWorlds,
					normalToDecalsDraw = drawCallChunk.normalToDecals,
					renderingLayerMasksDraw = drawCallChunk.renderingLayerMasks,
					subCalls = drawCallChunk.subCalls,
					subCallCount = drawCallChunk.subCallCounts
				}.Schedule(cachedChunk.currentJobHandle));
				cachedChunk.currentJobHandle = currentJobHandle;
			}
		}
	}
	internal abstract class DecalDrawSystem
	{
		internal static readonly uint MaxBatchSize = 250u;

		protected DecalEntityManager m_EntityManager;

		private Matrix4x4[] m_WorldToDecals;

		private Matrix4x4[] m_NormalToDecals;

		private float[] m_DecalLayerMasks;

		private ProfilingSampler m_Sampler;

		public Material overrideMaterial { get; set; }

		public DecalDrawSystem(string sampler, DecalEntityManager entityManager)
		{
			m_EntityManager = entityManager;
			m_WorldToDecals = new Matrix4x4[MaxBatchSize];
			m_NormalToDecals = new Matrix4x4[MaxBatchSize];
			m_DecalLayerMasks = new float[MaxBatchSize];
			m_Sampler = new ProfilingSampler(sampler);
		}

		public void Execute(CommandBuffer cmd)
		{
			Execute(CommandBufferHelpers.GetRasterCommandBuffer(cmd));
		}

		internal void Execute(RasterCommandBuffer cmd)
		{
			using (new ProfilingScope(cmd, m_Sampler))
			{
				for (int i = 0; i < m_EntityManager.chunkCount; i++)
				{
					Execute(cmd, m_EntityManager.entityChunks[i], m_EntityManager.cachedChunks[i], m_EntityManager.drawCallChunks[i], m_EntityManager.entityChunks[i].count);
				}
			}
		}

		protected virtual Material GetMaterial(DecalEntityChunk decalEntityChunk)
		{
			return decalEntityChunk.material;
		}

		protected abstract int GetPassIndex(DecalCachedChunk decalCachedChunk);

		private void Execute(RasterCommandBuffer cmd, DecalEntityChunk decalEntityChunk, DecalCachedChunk decalCachedChunk, DecalDrawCallChunk decalDrawCallChunk, int count)
		{
			decalCachedChunk.currentJobHandle.Complete();
			decalDrawCallChunk.currentJobHandle.Complete();
			Material material = GetMaterial(decalEntityChunk);
			int passIndex = GetPassIndex(decalCachedChunk);
			if (count != 0 && passIndex != -1 && !(material == null))
			{
				if (SystemInfo.supportsInstancing && material.enableInstancing)
				{
					DrawInstanced(cmd, decalEntityChunk, decalCachedChunk, decalDrawCallChunk, passIndex);
				}
				else
				{
					Draw(cmd, decalEntityChunk, decalCachedChunk, decalDrawCallChunk, passIndex);
				}
			}
		}

		private void Draw(RasterCommandBuffer cmd, DecalEntityChunk decalEntityChunk, DecalCachedChunk decalCachedChunk, DecalDrawCallChunk decalDrawCallChunk, int passIndex)
		{
			Mesh decalProjectorMesh = m_EntityManager.decalProjectorMesh;
			Material material = GetMaterial(decalEntityChunk);
			decalCachedChunk.propertyBlock.SetVector("unity_LightData", new Vector4(1f, 1f, 1f, 0f));
			int subCallCount = decalDrawCallChunk.subCallCount;
			for (int i = 0; i < subCallCount; i++)
			{
				DecalSubDrawCall decalSubDrawCall = decalDrawCallChunk.subCalls[i];
				for (int j = decalSubDrawCall.start; j < decalSubDrawCall.end; j++)
				{
					decalCachedChunk.propertyBlock.SetMatrix("_NormalToWorld", decalDrawCallChunk.normalToDecals[j]);
					decalCachedChunk.propertyBlock.SetFloat("_DecalLayerMaskFromDecal", decalDrawCallChunk.renderingLayerMasks[j]);
					cmd.DrawMesh(decalProjectorMesh, decalDrawCallChunk.decalToWorlds[j], material, 0, passIndex, decalCachedChunk.propertyBlock);
				}
			}
		}

		private void DrawInstanced(RasterCommandBuffer cmd, DecalEntityChunk decalEntityChunk, DecalCachedChunk decalCachedChunk, DecalDrawCallChunk decalDrawCallChunk, int passIndex)
		{
			Mesh decalProjectorMesh = m_EntityManager.decalProjectorMesh;
			Material material = GetMaterial(decalEntityChunk);
			decalCachedChunk.propertyBlock.SetVector("unity_LightData", new Vector4(1f, 1f, 1f, 0f));
			int subCallCount = decalDrawCallChunk.subCallCount;
			for (int i = 0; i < subCallCount; i++)
			{
				DecalSubDrawCall decalSubDrawCall = decalDrawCallChunk.subCalls[i];
				NativeArray<Matrix4x4>.Copy(decalDrawCallChunk.decalToWorlds.Reinterpret<Matrix4x4>(), decalSubDrawCall.start, m_WorldToDecals, 0, decalSubDrawCall.count);
				NativeArray<Matrix4x4>.Copy(decalDrawCallChunk.normalToDecals.Reinterpret<Matrix4x4>(), decalSubDrawCall.start, m_NormalToDecals, 0, decalSubDrawCall.count);
				NativeArray<float>.Copy(decalDrawCallChunk.renderingLayerMasks.Reinterpret<float>(), decalSubDrawCall.start, m_DecalLayerMasks, 0, decalSubDrawCall.count);
				decalCachedChunk.propertyBlock.SetMatrixArray("_NormalToWorld", m_NormalToDecals);
				decalCachedChunk.propertyBlock.SetFloatArray("_DecalLayerMaskFromDecal", m_DecalLayerMasks);
				cmd.DrawMeshInstanced(decalProjectorMesh, 0, material, passIndex, m_WorldToDecals, decalSubDrawCall.end - decalSubDrawCall.start, decalCachedChunk.propertyBlock);
			}
		}

		public void Execute(in CameraData cameraData)
		{
			using (new ProfilingScope(m_Sampler))
			{
				for (int i = 0; i < m_EntityManager.chunkCount; i++)
				{
					Execute(in cameraData, m_EntityManager.entityChunks[i], m_EntityManager.cachedChunks[i], m_EntityManager.drawCallChunks[i], m_EntityManager.entityChunks[i].count);
				}
			}
		}

		private void Execute(in CameraData cameraData, DecalEntityChunk decalEntityChunk, DecalCachedChunk decalCachedChunk, DecalDrawCallChunk decalDrawCallChunk, int count)
		{
			decalCachedChunk.currentJobHandle.Complete();
			decalDrawCallChunk.currentJobHandle.Complete();
			Material material = GetMaterial(decalEntityChunk);
			int passIndex = GetPassIndex(decalCachedChunk);
			if (count != 0 && passIndex != -1 && !(material == null))
			{
				if (SystemInfo.supportsInstancing && material.enableInstancing)
				{
					DrawInstanced(in cameraData, decalEntityChunk, decalCachedChunk, decalDrawCallChunk);
				}
				else
				{
					Draw(in cameraData, decalEntityChunk, decalCachedChunk, decalDrawCallChunk);
				}
			}
		}

		private void Draw(in CameraData cameraData, DecalEntityChunk decalEntityChunk, DecalCachedChunk decalCachedChunk, DecalDrawCallChunk decalDrawCallChunk)
		{
			Mesh decalProjectorMesh = m_EntityManager.decalProjectorMesh;
			Material material = GetMaterial(decalEntityChunk);
			int subCallCount = decalDrawCallChunk.subCallCount;
			for (int i = 0; i < subCallCount; i++)
			{
				DecalSubDrawCall decalSubDrawCall = decalDrawCallChunk.subCalls[i];
				for (int j = decalSubDrawCall.start; j < decalSubDrawCall.end; j++)
				{
					decalCachedChunk.propertyBlock.SetMatrix("_NormalToWorld", decalDrawCallChunk.normalToDecals[j]);
					decalCachedChunk.propertyBlock.SetFloat("_DecalLayerMaskFromDecal", decalDrawCallChunk.renderingLayerMasks[j]);
					Graphics.DrawMesh(decalProjectorMesh, decalDrawCallChunk.decalToWorlds[j], material, decalCachedChunk.layerMasks[j], cameraData.camera, 0, decalCachedChunk.propertyBlock);
				}
			}
		}

		private void DrawInstanced(in CameraData cameraData, DecalEntityChunk decalEntityChunk, DecalCachedChunk decalCachedChunk, DecalDrawCallChunk decalDrawCallChunk)
		{
			Mesh decalProjectorMesh = m_EntityManager.decalProjectorMesh;
			Material material = GetMaterial(decalEntityChunk);
			decalCachedChunk.propertyBlock.SetVector("unity_LightData", new Vector4(1f, 1f, 1f, 0f));
			int subCallCount = decalDrawCallChunk.subCallCount;
			for (int i = 0; i < subCallCount; i++)
			{
				DecalSubDrawCall decalSubDrawCall = decalDrawCallChunk.subCalls[i];
				NativeArray<Matrix4x4>.Copy(decalDrawCallChunk.decalToWorlds.Reinterpret<Matrix4x4>(), decalSubDrawCall.start, m_WorldToDecals, 0, decalSubDrawCall.count);
				NativeArray<Matrix4x4>.Copy(decalDrawCallChunk.normalToDecals.Reinterpret<Matrix4x4>(), decalSubDrawCall.start, m_NormalToDecals, 0, decalSubDrawCall.count);
				NativeArray<float>.Copy(decalDrawCallChunk.renderingLayerMasks.Reinterpret<float>(), decalSubDrawCall.start, m_DecalLayerMasks, 0, decalSubDrawCall.count);
				decalCachedChunk.propertyBlock.SetMatrixArray("_NormalToWorld", m_NormalToDecals);
				decalCachedChunk.propertyBlock.SetFloatArray("_DecalLayerMaskFromDecal", m_DecalLayerMasks);
				Graphics.DrawMeshInstanced(decalProjectorMesh, 0, material, m_WorldToDecals, decalSubDrawCall.count, decalCachedChunk.propertyBlock, ShadowCastingMode.On, receiveShadows: true, 0, cameraData.camera);
			}
		}
	}
	internal class DecalEntityIndexer
	{
		public struct DecalEntityItem
		{
			public int chunkIndex;

			public int arrayIndex;

			public int version;
		}

		private List<DecalEntityItem> m_Entities = new List<DecalEntityItem>();

		private Queue<int> m_FreeIndices = new Queue<int>();

		public bool IsValid(DecalEntity decalEntity)
		{
			if (m_Entities.Count <= decalEntity.index)
			{
				return false;
			}
			return m_Entities[decalEntity.index].version == decalEntity.version;
		}

		public DecalEntity CreateDecalEntity(int arrayIndex, int chunkIndex)
		{
			if (m_FreeIndices.Count != 0)
			{
				int index = m_FreeIndices.Dequeue();
				int version = m_Entities[index].version + 1;
				m_Entities[index] = new DecalEntityItem
				{
					arrayIndex = arrayIndex,
					chunkIndex = chunkIndex,
					version = version
				};
				return new DecalEntity
				{
					index = index,
					version = version
				};
			}
			int count = m_Entities.Count;
			int version2 = 1;
			m_Entities.Add(new DecalEntityItem
			{
				arrayIndex = arrayIndex,
				chunkIndex = chunkIndex,
				version = version2
			});
			return new DecalEntity
			{
				index = count,
				version = version2
			};
		}

		public void DestroyDecalEntity(DecalEntity decalEntity)
		{
			m_FreeIndices.Enqueue(decalEntity.index);
			DecalEntityItem value = m_Entities[decalEntity.index];
			value.version++;
			m_Entities[decalEntity.index] = value;
		}

		public DecalEntityItem GetItem(DecalEntity decalEntity)
		{
			return m_Entities[decalEntity.index];
		}

		public void UpdateIndex(DecalEntity decalEntity, int newArrayIndex)
		{
			DecalEntityItem value = m_Entities[decalEntity.index];
			value.arrayIndex = newArrayIndex;
			value.version = decalEntity.version;
			m_Entities[decalEntity.index] = value;
		}

		public void RemapChunkIndices(List<int> remaper)
		{
			for (int i = 0; i < m_Entities.Count; i++)
			{
				int chunkIndex = remaper[m_Entities[i].chunkIndex];
				DecalEntityItem value = m_Entities[i];
				value.chunkIndex = chunkIndex;
				m_Entities[i] = value;
			}
		}

		public void Clear()
		{
			m_Entities.Clear();
			m_FreeIndices.Clear();
		}
	}
	internal struct DecalEntity
	{
		public int index;

		public int version;
	}
	internal class DecalEntityChunk : DecalChunk
	{
		public Material material;

		public NativeArray<DecalEntity> decalEntities;

		public DecalProjector[] decalProjectors;

		public TransformAccessArray transformAccessArray;

		public override void Push()
		{
			base.count++;
		}

		public override void RemoveAtSwapBack(int entityIndex)
		{
			RemoveAtSwapBack(ref decalEntities, entityIndex, base.count);
			RemoveAtSwapBack(ref decalProjectors, entityIndex, base.count);
			transformAccessArray.RemoveAtSwapBack(entityIndex);
			base.count--;
		}

		public override void SetCapacity(int newCapacity)
		{
			ArrayExtensions.ResizeArray(ref decalEntities, newCapacity);
			ResizeNativeArray(ref transformAccessArray, decalProjectors, newCapacity);
			ArrayExtensions.ResizeArray(ref decalProjectors, newCapacity);
			base.capacity = newCapacity;
		}

		public override void Dispose()
		{
			if (base.capacity != 0)
			{
				decalEntities.Dispose();
				transformAccessArray.Dispose();
				decalProjectors = null;
				base.count = 0;
				base.capacity = 0;
			}
		}
	}
	internal class DecalEntityManager : IDisposable
	{
		private struct CombinedChunks
		{
			public DecalEntityChunk entityChunk;

			public DecalCachedChunk cachedChunk;

			public DecalCulledChunk culledChunk;

			public DecalDrawCallChunk drawCallChunk;

			public int previousChunkIndex;

			public bool valid;
		}

		public List<DecalEntityChunk> entityChunks = new List<DecalEntityChunk>();

		public List<DecalCachedChunk> cachedChunks = new List<DecalCachedChunk>();

		public List<DecalCulledChunk> culledChunks = new List<DecalCulledChunk>();

		public List<DecalDrawCallChunk> drawCallChunks = new List<DecalDrawCallChunk>();

		public int chunkCount;

		private ProfilingSampler m_AddDecalSampler;

		private ProfilingSampler m_ResizeChunks;

		private ProfilingSampler m_SortChunks;

		private DecalEntityIndexer m_DecalEntityIndexer = new DecalEntityIndexer();

		private Dictionary<Material, int> m_MaterialToChunkIndex = new Dictionary<Material, int>();

		private List<CombinedChunks> m_CombinedChunks = new List<CombinedChunks>();

		private List<int> m_CombinedChunkRemmap = new List<int>();

		private Material m_ErrorMaterial;

		private Mesh m_DecalProjectorMesh;

		public Material errorMaterial
		{
			get
			{
				if (m_ErrorMaterial == null)
				{
					m_ErrorMaterial = CoreUtils.CreateEngineMaterial(Shader.Find("Hidden/InternalErrorShader"));
				}
				return m_ErrorMaterial;
			}
		}

		public Mesh decalProjectorMesh
		{
			get
			{
				if (m_DecalProjectorMesh == null)
				{
					m_DecalProjectorMesh = CoreUtils.CreateCubeMesh(new Vector4(-0.5f, -0.5f, -0.5f, 1f), new Vector4(0.5f, 0.5f, 0.5f, 1f));
				}
				return m_DecalProjectorMesh;
			}
		}

		public DecalEntityManager()
		{
			m_AddDecalSampler = new ProfilingSampler("DecalEntityManager.CreateDecalEntity");
			m_ResizeChunks = new ProfilingSampler("DecalEntityManager.ResizeChunks");
			m_SortChunks = new ProfilingSampler("DecalEntityManager.SortChunks");
		}

		public bool IsValid(DecalEntity decalEntity)
		{
			return m_DecalEntityIndexer.IsValid(decalEntity);
		}

		public DecalEntity CreateDecalEntity(DecalProjector decalProjector)
		{
			Material material = decalProjector.material;
			if (material == null)
			{
				material = errorMaterial;
			}
			using (new ProfilingScope(m_AddDecalSampler))
			{
				int num = CreateChunkIndex(material);
				int count = entityChunks[num].count;
				DecalEntity decalEntity = m_DecalEntityIndexer.CreateDecalEntity(count, num);
				DecalEntityChunk decalEntityChunk = entityChunks[num];
				DecalCachedChunk decalCachedChunk = cachedChunks[num];
				DecalCulledChunk decalCulledChunk = culledChunks[num];
				DecalDrawCallChunk decalDrawCallChunk = drawCallChunks[num];
				if (entityChunks[num].capacity == entityChunks[num].count)
				{
					using (new ProfilingScope(m_ResizeChunks))
					{
						int y = entityChunks[num].capacity + entityChunks[num].capacity;
						y = math.max(8, y);
						decalEntityChunk.SetCapacity(y);
						decalCachedChunk.SetCapacity(y);
						decalCulledChunk.SetCapacity(y);
						decalDrawCallChunk.SetCapacity(y);
					}
				}
				decalEntityChunk.Push();
				decalCachedChunk.Push();
				decalCulledChunk.Push();
				decalDrawCallChunk.Push();
				decalEntityChunk.decalProjectors[count] = decalProjector;
				decalEntityChunk.decalEntities[count] = decalEntity;
				decalEntityChunk.transformAccessArray.Add(decalProjector.transform);
				UpdateDecalEntityData(decalEntity, decalProjector);
				return decalEntity;
			}
		}

		private int CreateChunkIndex(Material material)
		{
			if (!m_MaterialToChunkIndex.TryGetValue(material, out var value))
			{
				MaterialPropertyBlock materialPropertyBlock = new MaterialPropertyBlock();
				materialPropertyBlock.SetMatrixArray("_NormalToWorld", new Matrix4x4[DecalDrawSystem.MaxBatchSize]);
				materialPropertyBlock.SetFloatArray("_DecalLayerMaskFromDecal", new float[DecalDrawSystem.MaxBatchSize]);
				entityChunks.Add(new DecalEntityChunk
				{
					material = material
				});
				cachedChunks.Add(new DecalCachedChunk
				{
					propertyBlock = materialPropertyBlock
				});
				culledChunks.Add(new DecalCulledChunk());
				drawCallChunks.Add(new DecalDrawCallChunk
				{
					subCallCounts = new NativeArray<int>(1, Allocator.Persistent)
				});
				m_CombinedChunks.Add(default(CombinedChunks));
				m_CombinedChunkRemmap.Add(0);
				m_MaterialToChunkIndex.Add(material, chunkCount);
				return chunkCount++;
			}
			return value;
		}

		public void UpdateAllDecalEntitiesData()
		{
			foreach (DecalEntityChunk entityChunk in entityChunks)
			{
				for (int i = 0; i < entityChunk.count; i++)
				{
					DecalProjector decalProjector = entityChunk.decalProjectors[i];
					if (!(decalProjector == null))
					{
						DecalEntity decalEntity = entityChunk.decalEntities[i];
						if (IsValid(decalEntity))
						{
							UpdateDecalEntityData(decalEntity, decalProjector);
						}
					}
				}
			}
		}

		public void UpdateDecalEntityData(DecalEntity decalEntity, DecalProjector decalProjector)
		{
			DecalEntityIndexer.DecalEntityItem item = m_DecalEntityIndexer.GetItem(decalEntity);
			int chunkIndex = item.chunkIndex;
			int arrayIndex = item.arrayIndex;
			DecalCachedChunk decalCachedChunk = cachedChunks[chunkIndex];
			decalCachedChunk.sizeOffsets[arrayIndex] = Matrix4x4.Translate(decalProjector.decalOffset) * Matrix4x4.Scale(decalProjector.decalSize);
			float drawDistance = decalProjector.drawDistance;
			float fadeScale = decalProjector.fadeScale;
			float startAngleFade = decalProjector.startAngleFade;
			float endAngleFade = decalProjector.endAngleFade;
			Vector4 uvScaleBias = decalProjector.uvScaleBias;
			int layer = decalProjector.gameObject.layer;
			ulong sceneCullingMask = decalProjector.gameObject.sceneCullingMask;
			float fadeFactor = decalProjector.fadeFactor;
			decalCachedChunk.drawDistances[arrayIndex] = new Vector2(drawDistance, fadeScale);
			if (startAngleFade == 180f)
			{
				decalCachedChunk.angleFades[arrayIndex] = new Vector2(0f, 0f);
			}
			else
			{
				float num = startAngleFade / 180f;
				float num2 = endAngleFade / 180f;
				float num3 = Mathf.Max(0.0001f, num2 - num);
				decalCachedChunk.angleFades[arrayIndex] = new Vector2(1f - (0.25f - num) / num3, -0.25f / num3);
			}
			decalCachedChunk.uvScaleBias[arrayIndex] = uvScaleBias;
			decalCachedChunk.layerMasks[arrayIndex] = layer;
			decalCachedChunk.sceneLayerMasks[arrayIndex] = sceneCullingMask;
			decalCachedChunk.fadeFactors[arrayIndex] = fadeFactor;
			decalCachedChunk.scaleModes[arrayIndex] = decalProjector.scaleMode;
			decalCachedChunk.renderingLayerMasks[arrayIndex] = RenderingLayerUtils.ToValidRenderingLayers(decalProjector.renderingLayerMask);
			decalCachedChunk.positions[arrayIndex] = decalProjector.transform.position;
			decalCachedChunk.rotation[arrayIndex] = decalProjector.transform.rotation;
			decalCachedChunk.scales[arrayIndex] = decalProjector.transform.lossyScale;
			decalCachedChunk.dirty[arrayIndex] = true;
		}

		public void DestroyDecalEntity(DecalEntity decalEntity)
		{
			if (m_DecalEntityIndexer.IsValid(decalEntity))
			{
				DecalEntityIndexer.DecalEntityItem item = m_DecalEntityIndexer.GetItem(decalEntity);
				m_DecalEntityIndexer.DestroyDecalEntity(decalEntity);
				int chunkIndex = item.chunkIndex;
				int arrayIndex = item.arrayIndex;
				DecalEntityChunk decalEntityChunk = entityChunks[chunkIndex];
				DecalCachedChunk decalCachedChunk = cachedChunks[chunkIndex];
				DecalCulledChunk decalCulledChunk = culledChunks[chunkIndex];
				DecalDrawCallChunk decalDrawCallChunk = drawCallChunks[chunkIndex];
				int num = decalEntityChunk.count - 1;
				if (arrayIndex != num)
				{
					m_DecalEntityIndexer.UpdateIndex(decalEntityChunk.decalEntities[num], arrayIndex);
				}
				decalEntityChunk.RemoveAtSwapBack(arrayIndex);
				decalCachedChunk.RemoveAtSwapBack(arrayIndex);
				decalCulledChunk.RemoveAtSwapBack(arrayIndex);
				decalDrawCallChunk.RemoveAtSwapBack(arrayIndex);
			}
		}

		public void Update()
		{
			using (new ProfilingScope(m_SortChunks))
			{
				for (int i = 0; i < chunkCount; i++)
				{
					if (entityChunks[i].material == null)
					{
						entityChunks[i].material = errorMaterial;
					}
				}
				for (int j = 0; j < chunkCount; j++)
				{
					m_CombinedChunks[j] = new CombinedChunks
					{
						entityChunk = entityChunks[j],
						cachedChunk = cachedChunks[j],
						culledChunk = culledChunks[j],
						drawCallChunk = drawCallChunks[j],
						previousChunkIndex = j,
						valid = (entityChunks[j].count != 0)
					};
				}
				m_CombinedChunks.Sort(delegate(CombinedChunks a, CombinedChunks b)
				{
					if (a.valid && !b.valid)
					{
						return -1;
					}
					if (!a.valid && b.valid)
					{
						return 1;
					}
					if (a.cachedChunk.drawOrder < b.cachedChunk.drawOrder)
					{
						return -1;
					}
					return (a.cachedChunk.drawOrder > b.cachedChunk.drawOrder) ? 1 : a.entityChunk.material.GetHashCode().CompareTo(b.entityChunk.material.GetHashCode());
				});
				bool flag = false;
				for (int num = 0; num < chunkCount; num++)
				{
					if (m_CombinedChunks[num].previousChunkIndex != num || !m_CombinedChunks[num].valid)
					{
						flag = true;
						break;
					}
				}
				if (!flag)
				{
					return;
				}
				int num2 = 0;
				m_MaterialToChunkIndex.Clear();
				for (int num3 = 0; num3 < chunkCount; num3++)
				{
					CombinedChunks combinedChunks = m_CombinedChunks[num3];
					if (!m_CombinedChunks[num3].valid)
					{
						combinedChunks.entityChunk.currentJobHandle.Complete();
						combinedChunks.cachedChunk.currentJobHandle.Complete();
						combinedChunks.culledChunk.currentJobHandle.Complete();
						combinedChunks.drawCallChunk.currentJobHandle.Complete();
						combinedChunks.entityChunk.Dispose();
						combinedChunks.cachedChunk.Dispose();
						combinedChunks.culledChunk.Dispose();
						combinedChunks.drawCallChunk.Dispose();
						continue;
					}
					entityChunks[num3] = combinedChunks.entityChunk;
					cachedChunks[num3] = combinedChunks.cachedChunk;
					culledChunks[num3] = combinedChunks.culledChunk;
					drawCallChunks[num3] = combinedChunks.drawCallChunk;
					if (!m_MaterialToChunkIndex.ContainsKey(entityChunks[num3].material))
					{
						m_MaterialToChunkIndex.Add(entityChunks[num3].material, num3);
					}
					m_CombinedChunkRemmap[combinedChunks.previousChunkIndex] = num3;
					num2++;
				}
				if (chunkCount > num2)
				{
					entityChunks.RemoveRange(num2, chunkCount - num2);
					cachedChunks.RemoveRange(num2, chunkCount - num2);
					culledChunks.RemoveRange(num2, chunkCount - num2);
					drawCallChunks.RemoveRange(num2, chunkCount - num2);
					m_CombinedChunks.RemoveRange(num2, chunkCount - num2);
					chunkCount = num2;
				}
				m_DecalEntityIndexer.RemapChunkIndices(m_CombinedChunkRemmap);
			}
		}

		public void Dispose()
		{
			CoreUtils.Destroy(m_ErrorMaterial);
			CoreUtils.Destroy(m_DecalProjectorMesh);
			foreach (DecalEntityChunk entityChunk in entityChunks)
			{
				entityChunk.currentJobHandle.Complete();
			}
			foreach (DecalCachedChunk cachedChunk in cachedChunks)
			{
				cachedChunk.currentJobHandle.Complete();
			}
			foreach (DecalCulledChunk culledChunk in culledChunks)
			{
				culledChunk.currentJobHandle.Complete();
			}
			foreach (DecalDrawCallChunk drawCallChunk in drawCallChunks)
			{
				drawCallChunk.currentJobHandle.Complete();
			}
			foreach (DecalEntityChunk entityChunk2 in entityChunks)
			{
				entityChunk2.Dispose();
			}
			foreach (DecalCachedChunk cachedChunk2 in cachedChunks)
			{
				cachedChunk2.Dispose();
			}
			foreach (DecalCulledChunk culledChunk2 in culledChunks)
			{
				culledChunk2.Dispose();
			}
			foreach (DecalDrawCallChunk drawCallChunk2 in drawCallChunks)
			{
				drawCallChunk2.Dispose();
			}
			m_DecalEntityIndexer.Clear();
			m_MaterialToChunkIndex.Clear();
			entityChunks.Clear();
			cachedChunks.Clear();
			culledChunks.Clear();
			drawCallChunks.Clear();
			m_CombinedChunks.Clear();
			chunkCount = 0;
		}
	}
