					m_PreviousPreviousProjection[num5] = gPUProjectionMatrix;
					m_PreviousProjection[num5] = gPUProjectionMatrix;
					m_Projection[num5] = gPUProjectionMatrix;
					m_PreviousPreviousView[num5] = viewMatrix;
					m_PreviousView[num5] = viewMatrix;
					m_View[num5] = viewMatrix;
					m_ViewProjection[num5] = matrix4x;
					m_PreviousViewProjection[num5] = matrix4x;
				}
				m_PreviousPreviousProjection[num5] = m_PreviousProjection[num5];
				m_PreviousProjection[num5] = m_Projection[num5];
				m_Projection[num5] = gPUProjectionMatrix;
				m_PreviousPreviousView[num5] = m_PreviousView[num5];
				m_PreviousView[num5] = m_View[num5];
				m_View[num5] = viewMatrix;
				m_PreviousViewProjection[num5] = m_ViewProjection[num5];
				m_ViewProjection[num5] = matrix4x;
			}
			m_LastFrameIndex[xRMultiPassId] = frameCount;
			m_PrevAspectRatio[xRMultiPassId] = cameraData.aspectRatio;
		}

		public void SetGlobalMotionMatrices(RasterCommandBuffer cmd, XRPass xr)
		{
			int xRMultiPassId = GetXRMultiPassId(xr);
			if (xr.enabled && xr.singlePassEnabled)
			{
				cmd.SetGlobalMatrixArray(ShaderPropertyId.previousViewProjectionNoJitterStereo, previousViewProjectionStereo);
				cmd.SetGlobalMatrixArray(ShaderPropertyId.viewProjectionNoJitterStereo, viewProjectionStereo);
			}
			else
			{
				cmd.SetGlobalMatrix(ShaderPropertyId.previousViewProjectionNoJitter, previousViewProjectionStereo[xRMultiPassId]);
				cmd.SetGlobalMatrix(ShaderPropertyId.viewProjectionNoJitter, viewProjectionStereo[xRMultiPassId]);
			}
		}
	}
	[StructLayout(LayoutKind.Sequential, Size = 1)]
	internal struct Sorting
	{
		public static ProfilingSampler s_QuickSortSampler = new ProfilingSampler("QuickSort");

		public static ProfilingSampler s_InsertionSortSampler = new ProfilingSampler("InsertionSort");

		public static void QuickSort<T>(T[] data, Func<T, T, int> compare)
		{
			using (new ProfilingScope(s_QuickSortSampler))
			{
				QuickSort(data, 0, data.Length - 1, compare);
			}
		}

		public static void QuickSort<T>(T[] data, int start, int end, Func<T, T, int> compare)
		{
			int num = end - start;
			if (num < 1)
			{
				return;
			}
			if (num < 8)
			{
				InsertionSort(data, start, end, compare);
			}
			else if (start < end)
			{
				int num2 = Partition(data, start, end, compare);
				if (num2 >= 1)
				{
					QuickSort(data, start, num2, compare);
				}
				if (num2 + 1 < end)
				{
					QuickSort(data, num2 + 1, end, compare);
				}
			}
		}

		private static T Median3Pivot<T>(T[] data, int start, int pivot, int end, Func<T, T, int> compare)
		{
			if (compare(data[end], data[start]) < 0)
			{
				Swap(start, end);
			}
			if (compare(data[pivot], data[start]) < 0)
			{
				Swap(start, pivot);
			}
			if (compare(data[end], data[pivot]) < 0)
			{
				Swap(pivot, end);
			}
			return data[pivot];
			void Swap(int a, int b)
			{
				T val = data[a];
				data[a] = data[b];
				data[b] = val;
			}
		}

		private static int Partition<T>(T[] data, int start, int end, Func<T, T, int> compare)
		{
			int num = end - start;
			int pivot = start + num / 2;
			T arg = Median3Pivot(data, start, pivot, end, compare);
			while (true)
			{
				if (compare(data[start], arg) < 0)
				{
					start++;
					continue;
				}
				while (compare(data[end], arg) > 0)
				{
					end--;
				}
				if (start >= end)
				{
					break;
				}
				T val = data[start];
				data[start++] = data[end];
				data[end--] = val;
			}
			return end;
		}

		public static void InsertionSort<T>(T[] data, Func<T, T, int> compare)
		{
			using (new ProfilingScope(s_InsertionSortSampler))
			{
				InsertionSort(data, 0, data.Length - 1, compare);
			}
		}

		public static void InsertionSort<T>(T[] data, int start, int end, Func<T, T, int> compare)
		{
			for (int i = start + 1; i < end + 1; i++)
			{
				T val = data[i];
				int num = i - 1;
				while (num >= 0 && compare(val, data[num]) < 0)
				{
					data[num + 1] = data[num];
					num--;
				}
				data[num + 1] = val;
			}
		}
	}
