					}
					ExecuteMainPass(rasterCommandBuffer, m_FetchActiveColor ? m_CopiedColor : null, m_Material, m_PassIndex);
				}
			}

			public override void RecordRenderGraph(RenderGraph renderGraph, ContextContainer frameData)
			{
