			}
			if (base.DebugHandler.TryGetFullscreenDebugMode(out var debugFullScreenMode, out var textureHeightPercent) && (debugFullScreenMode != DebugFullScreenMode.ReflectionProbeAtlas || usesClusterLightLoop))
			{
