					}
				}
				bool flag3 = data.shadowData.supportsMainLightShadows && data.lightData.mainLightIndex != -1 && visibleLights[data.lightData.mainLightIndex].light.shadows == LightShadows.Soft;
				bool flag4 = !data.stripShadowsOffVariants;
