				{
					break;
				}
				if (i == lightData.mainLightIndex)
				{
					lightIndexMap[i] = -1;
					num++;
					continue;
				}
				if (lightData.visibleLights[i].lightType == LightType.Directional || lightData.visibleLights[i].lightType == LightType.Spot || lightData.visibleLights[i].lightType == LightType.Point)
